mapper.select:
select r.id, r.order_id as orderId, o.number as orderNumber, r.dish_id as dishId, d.name as dishName, d.image as dishImage, r.rating, r.content, r.images as imagesJson, r.like_count as likeCount, r.status, r.ai_generated as aiGenerated, r.create_time as createTime, r.update_time as updateTime from dish_review r left join orders o on o.id = r.order_id left join dish d on d.id = r.dish_id where r.user_id = #{userId}
and r.order_id = #{queryDTO.orderId}
and r.dish_id = #{queryDTO.dishId}
order by r.create_time desc, r.id desc

mapper.update:
update dish_review
set status = #{status},
    update_time = #{updateTime}
where id = #{id}
